#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding pediatric-assessment (14 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_birth_history \
    assessment:references \
    gestational_age_weeks:int \
    birth_weight_grams:int \
    delivery_method:string! \
    apgar_score_1min:int \
    apgar_score_5min:int \
    nicu_admission:string! \
    nicu_duration_days:int \
    birth_complications:text! \
    maternal_complications:text! \
    preterm:string! \
    --htmx

cargo loco generate scaffold assessment_growth_nutrition \
    assessment:references \
    current_weight_kg:double \
    current_height_cm:double \
    head_circumference_cm:double \
    weight_percentile:int \
    height_percentile:int \
    bmi_percentile:int \
    feeding_method:string! \
    dietary_concerns:text! \
    appetite:string! \
    nutritional_supplements:string! \
    supplement_details:text! \
    growth_concerns:string! \
    growth_concern_details:text! \
    --htmx

cargo loco generate scaffold assessment_developmental_milestones \
    assessment:references \
    gross_motor_status:string! \
    gross_motor_details:text! \
    fine_motor_status:string! \
    fine_motor_details:text! \
    speech_language_status:string! \
    speech_language_details:text! \
    social_emotional_status:string! \
    social_emotional_details:text! \
    cognitive_status:string! \
    cognitive_details:text! \
    self_care_status:string! \
    self_care_details:text! \
    developmental_screening_tool:string! \
    developmental_screening_score:int \
    previous_developmental_concerns:string! \
    previous_concern_details:text! \
    early_intervention_referral:string! \
    --htmx

cargo loco generate scaffold assessment_immunization_status \
    assessment:references \
    immunization_up_to_date:string! \
    immunization_schedule:string! \
    missed_vaccinations:text! \
    vaccine_adverse_reactions:string! \
    adverse_reaction_details:text! \
    vaccine_exemptions:string! \
    exemption_reason:text! \
    bcg_given:string! \
    influenza_vaccine:string! \
    covid_vaccine:string! \
    last_vaccination_date:date \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    chronic_conditions:text! \
    previous_hospitalizations:string! \
    hospitalization_details:text! \
    previous_surgeries:string! \
    surgery_details:text! \
    known_allergies:string! \
    allergy_details:text! \
    congenital_conditions:string! \
    congenital_condition_details:text! \
    hearing_screen_passed:string! \
    vision_screen_passed:string! \
    recurrent_infections:string! \
    recurrent_infection_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_regular_medications:string! \
    takes_over_the_counter:string! \
    over_the_counter_details:text! \
    takes_supplements:string! \
    supplement_details:text! \
    medication_adherence:string! \
    adverse_drug_reactions:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    route:string! \
    indication:text! \
    prescribing_clinician:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_family_history \
    assessment:references \
    family_history_significant:string! \
    consanguinity:string! \
    genetic_conditions:string! \
    genetic_condition_details:text! \
    developmental_delays_family:string! \
    developmental_delay_details:text! \
    mental_health_family:string! \
    mental_health_details:text! \
    chronic_disease_family:string! \
    chronic_disease_details:text! \
    sudden_infant_death:string! \
    childhood_cancer_family:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_social_environmental \
    assessment:references \
    living_arrangement:string! \
    living_arrangement_details:text! \
    number_of_siblings:int \
    childcare_type:string! \
    school_type:string! \
    school_performance:string! \
    behavioural_concerns:string! \
    behavioural_concern_details:text! \
    social_services_involved:string! \
    safeguarding_concerns:string! \
    safeguarding_details:text! \
    household_smoking:string! \
    housing_concerns:string! \
    housing_concern_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    overall_outcome:string! \
    developmental_score:int \
    growth_classification:string! \
    environmental_risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    outcome:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
